@app.route('/api/v1/api-keys-internal/generate', methods=['POST'])
def generate_api_key_internal():
    """Generate API key from settings page (no auth required)."""
    from api.auth import generate_api_key
    body = request.get_json(silent=True) or {}
    label = body.get("label", "")
    raw_key, record = generate_api_key(label)
    keys = config_manager.get('api_keys', [])
    keys.append(record)
    config_manager.set('api_keys', keys)
    return jsonify({"success": True, "data": {
        "key": raw_key,
        "id": record["id"],
        "label": record["label"],
        "key_prefix": record["key_prefix"],
        "created_at": record["created_at"],
    }}), 201

@app.route('/api/v1/api-keys-internal/revoke/<key_id>', methods=['DELETE'])
def revoke_api_key_internal(key_id):
    """Revoke API key from settings page (no auth required)."""
    keys = config_manager.get('api_keys', [])
    original_len = len(keys)
    keys = [k for k in keys if k.get("id") != key_id]
    if len(keys) == original_len:
        return jsonify({"success": False, "error": {"message": "Key not found"}}), 404
    config_manager.set('api_keys', keys)
    return jsonify({"success": True, "data": {"message": "API key revoked"}})


@app.route('/api/settings', methods=['GET', 'POST'])
@admin_only
def handle_settings():
    global tidal_client # Declare that we might modify the global instance
    if not config_manager:
        return jsonify({"error": "Server configuration manager is not initialized."}), 500
    if request.method == 'POST':
        try:
            new_settings = request.get_json()
            if not new_settings:
                return jsonify({"success": False, "error": "No data received."}), 400

            if 'active_media_server' in new_settings:
                config_manager.set_active_media_server(new_settings['active_media_server'])

            for service in ['spotify', 'plex', 'jellyfin', 'navidrome', 'soulseek', 'download_source', 'settings', 'database', 'metadata_enhancement', 'file_organization', 'playlist_sync', 'tidal', 'tidal_download', 'qobuz', 'hifi_download', 'deezer_download', 'lidarr_download', 'listenbrainz', 'acoustid', 'lastfm', 'genius', 'import', 'lossy_copy', 'listening_stats', 'ui_appearance', 'youtube', 'content_filter', 'itunes', 'm3u_export', 'musicbrainz', 'deezer', 'audiodb', 'metadata', 'hydrabase', 'security', 'discogs', 'library', 'discover', 'wishlist', 'genre_whitelist', 'post_processing']:
                if service in new_settings:
                    for key, value in new_settings[service].items():
                        config_manager.set(f'{service}.{key}', value)

            logger.info("Settings saved successfully via Web UI.")
            
            # Add activity for settings save
            changed_services = list(new_settings.keys())
            services_text = ", ".join(changed_services)
            add_activity_item("", "Settings Updated", f"{services_text} configuration saved", "Now")
            
            add_activity_item("", "Settings Updated", f"{services_text} configuration saved", "Now")
            
            # Reload service clients with new settings (guard against None from partial init)
            if spotify_client:
                spotify_client.reload_config()
            if plex_client:
                plex_client.server = None
            if jellyfin_client:
                jellyfin_client.reload_config()
            if navidrome_client:
                navidrome_client.reload_config()
            # Reload orchestrator settings (download source mode, hybrid_primary, etc.)
            if soulseek_client:
                soulseek_client.reload_settings()
                # Reload YouTube client settings (rate limiting, cookies)
                if hasattr(soulseek_client, 'youtube'):
                    soulseek_client.youtube.reload_settings()
            # FIX: Re-instantiate the global tidal_client to pick up new settings
            try:
                tidal_client = TidalClient()
            except Exception:
                pass  # Keep existing tidal_client if re-init fails
            # Reload enrichment worker clients for key-based services
            if lastfm_worker:
                lastfm_worker._init_client()
            if genius_worker:
                genius_worker._init_client()
            if tidal_enrichment_worker:
                tidal_enrichment_worker.client = tidal_client
            if 'spotify' in new_settings:
                publish_spotify_status(
                    connected=False,
                    authenticated=False,
                    rate_limited=False,
                    rate_limit=None,
                    post_ban_cooldown=None,
                )
            # Invalidate status cache so next poll reflects new settings (e.g. fallback source change)
            invalidate_metadata_status_caches()
            logger.info("Service clients re-initialized with new settings.")
            return jsonify({"success": True, "message": "Settings saved successfully."})
        except Exception as e:
            return jsonify({"success": False, "error": str(e)}), 500
    else:  # GET request
        try:
            data = dict(config_manager.config_data)
            # Include which download sources are configured so the UI can auto-disable unconfigured ones
            try:
                data['_source_status'] = soulseek_client.get_source_status()
            except Exception:
                pass
            return jsonify(data)
        except Exception as e:
            return jsonify({"error": str(e)}), 500


