# In-memory ring buffer for live log streaming via WebSocket
_live_log_buffer = []
_live_log_buffer_lock = threading.Lock()
_LIVE_LOG_BUFFER_MAX = 500


@app.route('/api/logs/tail', methods=['GET'])
def get_log_tail():
    """Return the last N lines from a log file, optionally filtered by level."""
    log_source = request.args.get('source', 'app')
    lines = request.args.get('lines', 200, type=int)
    lines = max(10, min(lines, 1000))
    level_filter = request.args.get('level', '').upper()  # DEBUG, INFO, WARNING, ERROR or empty

    log_map = {
        'app': Path(_log_path),
        'acoustid': _log_dir / 'acoustid.log',
        'post_processing': _log_dir / 'post_processing.log',
        'source_reuse': _log_dir / 'source_reuse.log',
    }
    log_path = log_map.get(log_source, log_map['app'])

    search = request.args.get('search', '').lower()

    def _classify_log_level(line):
        """Classify a log line's level. Returns DEBUG/INFO/WARNING/ERROR or empty for unclassified."""
        if ' - DEBUG - ' in line: return 'DEBUG'
        if ' - INFO - ' in line: return 'INFO'
        if ' - WARNING - ' in line: return 'WARNING'
        if ' - ERROR - ' in line or ' - CRITICAL - ' in line: return 'ERROR'
        # Heuristic for plain-text output and non-logger lines
        ll = line.lower()
        if 'error' in ll or 'traceback' in ll or 'exception' in ll or 'failed' in ll: return 'ERROR'
        if 'warning' in ll or 'warn' in ll: return 'WARNING'
        if 'debug' in ll: return 'DEBUG'
        return 'INFO'  # Default unclassified lines to INFO

    result_lines = []
    if os.path.exists(log_path):
        try:
            with open(log_path, 'r', encoding='utf-8', errors='replace') as f:
                all_lines = f.readlines()
            # Read more lines than requested so filtering has enough to work with
            pool_size = lines * 5 if (level_filter or search) else lines
            tail = all_lines[-pool_size:]
            for line in tail:
                stripped = line.rstrip()
                if not stripped:
                    continue
                if level_filter and level_filter in ('DEBUG', 'INFO', 'WARNING', 'ERROR'):
                    if _classify_log_level(stripped) != level_filter:
                        continue
                if search and search not in stripped.lower():
                    continue
                result_lines.append(stripped)
            # Trim to requested count after filtering
            result_lines = result_lines[-lines:]
        except Exception as e:
            result_lines = [f'Error reading log file: {e}']

    # Available log files
    available = []
    logs_dir = 'logs'
    if os.path.isdir(logs_dir):
        for fname in sorted(os.listdir(logs_dir)):
            if fname.endswith('.log'):
                fpath = os.path.join(logs_dir, fname)
                size_kb = os.path.getsize(fpath) / 1024
                available.append({
                    'key': fname.replace('.log', ''),
                    'file': fname,
                    'size': f"{size_kb:.0f} KB" if size_kb < 1024 else f"{size_kb/1024:.1f} MB",
                })

    return jsonify({
        'lines': result_lines,
        'source': log_source,
        'total': len(result_lines),
        'available_logs': available,
    })


