_music_video_downloads = {}  # {video_id: {status, progress, path, error}}

@app.route('/api/music-video/download', methods=['POST'])
def download_music_video():
    """Download a YouTube video as a music video file to the configured music videos folder."""
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data"}), 400

    video_id = data.get('video_id', '')
    video_url = data.get('url', '')
    raw_title = data.get('title', '')
    raw_channel = data.get('channel', '')

    if not video_id or not video_url:
        return jsonify({"error": "Missing video_id or url"}), 400

    # Check if already downloading
    if video_id in _music_video_downloads and _music_video_downloads[video_id].get('status') == 'downloading':
        return jsonify({"error": "Already downloading"}), 409

    # Get and validate music videos path
    music_videos_path = config_manager.get('library.music_videos_path', '') or ''
    if not music_videos_path.strip():
        return jsonify({"error": "Music Videos directory not configured. Set it in Settings > Downloads."}), 400
    music_videos_path = docker_resolve_path(music_videos_path)
    try:
        os.makedirs(music_videos_path, exist_ok=True)
        # Quick write test
        test_file = os.path.join(music_videos_path, '.soulsync_write_test')
        with open(test_file, 'w') as f:
            f.write('test')
        os.remove(test_file)
    except (OSError, PermissionError) as e:
        return jsonify({"error": f"Music Videos directory is not writable: {e}"}), 400

    # Initialize download state
    _music_video_downloads[video_id] = {'status': 'searching', 'progress': 0, 'path': None, 'error': None}

    def _do_download():
        try:
            # Step 1: Try to match against primary metadata source for clean artist/title
            _music_video_downloads[video_id]['status'] = 'matching'
            artist_name = raw_channel
            track_title = raw_title
            year = ''

            # Strip common YouTube suffixes for cleaner search
            import re as _re
            clean_search = _re.sub(r'\s*[\(\[](official\s*(music\s*)?video|official\s*lyric\s*video|official\s*audio|official\s*hd|hd|4k|remastered|lyric\s*video|visualizer|audio)[\)\]]', '', raw_title, flags=_re.IGNORECASE).strip()
            clean_search = _re.sub(r'\s*-\s*$', '', clean_search).strip()

            try:
                fallback_client = _get_metadata_fallback_client()
                results = fallback_client.search_tracks(clean_search, limit=5)
                if results:
                    from difflib import SequenceMatcher
                    best = None
                    best_score = 0
                    for r in results:
                        name_sim = SequenceMatcher(None, clean_search.lower(), r.name.lower()).ratio()
                        if r.artists:
                            artist_sim = SequenceMatcher(None, raw_channel.lower(), r.artists[0].lower()).ratio()
                            name_sim = (name_sim * 0.6) + (artist_sim * 0.4)
                        if name_sim > best_score:
                            best_score = name_sim
                            best = r
                    if best and best_score >= 0.5:
                        artist_name = best.artists[0] if best.artists else raw_channel
                        track_title = best.name
                        if hasattr(best, 'release_date') and best.release_date:
                            year = str(best.release_date)[:4]
                        logger.info(f"[Music Video] Matched to: {artist_name} - {track_title} (confidence: {best_score:.2f})")
                    else:
                        # Parse artist from video title: "Artist - Title" pattern
                        if ' - ' in raw_title:
                            parts = raw_title.split(' - ', 1)
                            artist_name = parts[0].strip()
                            track_title = _re.sub(r'\s*[\(\[].*?[\)\]]', '', parts[1]).strip()
                        logger.warning(f"[Music Video] No metadata match, using parsed: {artist_name} - {track_title}")
            except Exception as e:
                logger.error(f"[Music Video] Metadata lookup failed: {e}")
                if ' - ' in raw_title:
                    parts = raw_title.split(' - ', 1)
                    artist_name = parts[0].strip()
                    track_title = _re.sub(r'\s*[\(\[].*?[\)\]]', '', parts[1]).strip()

            # Sanitize for filesystem
            def _sanitize(s):
                return _re.sub(r'[<>:"/\\|?*]', '_', s).strip().rstrip('.')

            # Apply video path template
            video_template = config_manager.get('file_organization.templates', {}).get('video_path', '$artist/$title-video')
            if not video_template or not video_template.strip():
                video_template = '$artist/$title-video'
            safe_artist = _sanitize(artist_name)
            video_path = video_template
            video_path = video_path.replace('$artistletter', safe_artist[0].upper() if safe_artist else 'A')
            video_path = video_path.replace('$artist', safe_artist)
            video_path = video_path.replace('$title', _sanitize(track_title))
            video_path = video_path.replace('$year', str(year) if year else '')
            # Clean up empty segments from missing variables
            video_path = _re.sub(r'//+', '/', video_path).strip('/')
            # Split into folder and filename
            path_parts = video_path.rsplit('/', 1)
            if len(path_parts) == 2:
                folder_part, file_part = path_parts
            else:
                folder_part, file_part = '', path_parts[0]
            output_dir = os.path.join(music_videos_path, folder_part) if folder_part else music_videos_path
            os.makedirs(output_dir, exist_ok=True)
            output_path = os.path.join(output_dir, file_part)

            # Step 2: Download
            _music_video_downloads[video_id]['status'] = 'downloading'
            _music_video_downloads[video_id]['artist'] = artist_name
            _music_video_downloads[video_id]['title'] = track_title

            def _progress(pct):
                _music_video_downloads[video_id]['progress'] = round(pct, 1)

            final_path = soulseek_client.youtube.download_music_video(video_url, output_path, progress_callback=_progress)

            if final_path and os.path.exists(final_path):
                _music_video_downloads[video_id]['status'] = 'completed'
                _music_video_downloads[video_id]['progress'] = 100
                _music_video_downloads[video_id]['path'] = final_path
                logger.info(f"[Music Video] Downloaded: {artist_name} - {track_title} → {final_path}")
                add_activity_item("", "Music Video Downloaded", f"{artist_name} - {track_title}", "Now")
            else:
                _music_video_downloads[video_id]['status'] = 'error'
                _music_video_downloads[video_id]['error'] = 'Download failed — file not found'
                logger.error(f"[Music Video] Download failed for: {artist_name} - {track_title}")

        except Exception as e:
            _music_video_downloads[video_id]['status'] = 'error'
            _music_video_downloads[video_id]['error'] = str(e)
            logger.error(f"[Music Video] {e}")

    # Run in background thread
    import threading
    threading.Thread(target=_do_download, daemon=True, name=f'music-video-{video_id}').start()

    return jsonify({"success": True, "video_id": video_id})


@app.route('/api/music-video/status/<video_id>', methods=['GET'])
def get_music_video_status(video_id):
    """Get download status for a music video."""
    status = _music_video_downloads.get(video_id)
    if not status:
        return jsonify({"status": "unknown"})
    return jsonify(status)


@app.route('/api/download', methods=['POST'])
def start_download():
    """Simple download route"""
    dl_err = check_download_permission()
    if dl_err:
        return dl_err
    data = request.get_json()
    if not data:
        return jsonify({"error": "No download data provided."}), 400
    
    try:
        result_type = data.get('result_type', 'track')
        
        if result_type == 'album':
            tracks = data.get('tracks', [])
            if not tracks:
                return jsonify({"error": "No tracks found in album."}), 400

            started_downloads = 0
            for track_data in tracks:
                try:
                    username = track_data.get('username')
                    filename = track_data.get('filename')
                    file_size = track_data.get('size', 0)

                    download_id = run_async(soulseek_client.download(
                        username,
                        filename,
                        file_size
                    ))
                    if download_id:
                        # Register download for post-processing (simple transfer to /Transfer)
                        context_key = _make_context_key(username, filename)
                        with matched_context_lock:
                            matched_downloads_context[context_key] = {
                                'search_result': {
                                    'username': username,
                                    'filename': filename,
                                    'size': file_size,
                                    'title': track_data.get('title', 'Unknown'),
                                    'artist': track_data.get('artist', 'Unknown'),
                                    'quality': track_data.get('quality', 'Unknown'),
                                    'is_simple_download': True  # Flag for simple processing
                                },
                                'spotify_artist': None,  # No Spotify metadata
                                'spotify_album': None,
                                'track_info': None
                            }
                        started_downloads += 1
                except Exception as e:
                    logger.error(f"Failed to start track download: {e}")
                    continue

            # Add activity for album download start
            album_name = data.get('album_name', 'Unknown Album')
            logger.info(f"Starting simple album download: '{album_name}' with {started_downloads}/{len(tracks)} tracks")
            add_activity_item("", "Album Download Started", f"'{album_name}' - {started_downloads} tracks", "Now")

            return jsonify({
                "success": True,
                "message": f"Started {started_downloads} downloads from album"
            })
        
        else:
            # Single track download
            username = data.get('username')
            filename = data.get('filename')
            file_size = data.get('size', 0)

            logger.info(f"Download request - Username: {username}, Filename: {filename[:50]}...")

            if not username or not filename:
                return jsonify({"error": "Missing username or filename."}), 400

            download_id = run_async(soulseek_client.download(username, filename, file_size))
            logger.info(f"Download ID returned: {download_id}")

            if download_id:
                # Register download for post-processing (simple transfer to /Transfer)
                context_key = _make_context_key(username, filename)
                is_streaming_source = username in ('youtube', 'tidal', 'qobuz', 'hifi', 'deezer_dl', 'lidarr')
                with matched_context_lock:
                    matched_downloads_context[context_key] = {
                        'search_result': {
                            'username': username,
                            'filename': filename,
                            'size': file_size,
                            'title': data.get('title', 'Unknown'),
                            'artist': data.get('artist', 'Unknown'),
                            'quality': data.get('quality', 'Unknown'),
                            'is_simple_download': True  # Flag for simple processing
                        },
                        'spotify_artist': None,  # No Spotify metadata
                        'spotify_album': None,
                        'track_info': None
                    }
                    source_label = username.title() if is_streaming_source else 'Soulseek'
                    logger.info(f"[{source_label}] Registered simple download for post-processing: {context_key}")

                # Extract track name from filename for activity
                track_name = filename.split('/')[-1] if '/' in filename else filename.split('\\')[-1] if '\\' in filename else filename
                logger.info(f"Starting simple track download: '{track_name}'")
                add_activity_item("", "Track Download Started", f"'{track_name}'", "Now")
                return jsonify({"success": True, "message": "Download started"})
            else:
                logger.error(f"Failed to start download for: {filename}")
                return jsonify({"error": "Failed to start download"}), 500
                
    except Exception as e:
        logger.error(f"Download error: {e}")
        return jsonify({"error": str(e)}), 500











def _find_completed_file_robust(download_dir, api_filename, transfer_dir=None):
    """
    Robustly finds a completed file on disk, accounting for name variations and
    unexpected subdirectories. This version uses the superior normalization logic
    from the GUI's matching_engine.py to ensure consistency.

    First searches in download_dir, then optionally searches in transfer_dir if provided.
    Returns tuple (file_path, location) where location is 'downloads' or 'transfer'.
    """
    import re
    import os
    from difflib import SequenceMatcher
    from unidecode import unidecode

    # YOUTUBE/TIDAL SUPPORT: Handle encoded filename format "id||title"
    # Extract just the title part for file matching
    if '||' in api_filename:
        _, title = api_filename.split('||', 1)
        api_filename = title  # Use just the title for file searching

    def normalize_for_finding(text: str) -> str:
        """A powerful normalization function adapted from matching_engine.py."""
        if not text: return ""
        text = unidecode(text).lower()
        # Replace common separators with spaces to preserve word boundaries
        text = re.sub(r'[._/]', ' ', text)
        # Keep alphanumeric, spaces, and hyphens. Remove brackets/parentheses content.
        text = re.sub(r'[\[\(].*?[\]\)]', '', text)
        text = re.sub(r'[^a-z0-9\s-]', '', text)
        # Consolidate multiple spaces
        return ' '.join(text.split()).strip()

    def _path_matches_api_dirs(file_path):
        """Check if ALL api directory components appear in the file's path."""
        path_parts = set(p.lower() for p in file_path.replace('\\', '/').split('/'))
        return all(d in path_parts for d in api_dir_parts)

    def search_in_directory(search_dir, location_name):
        """Search for the file in a specific directory."""
        best_fuzzy_path = None
        highest_fuzzy_similarity = 0.0
        exact_matches = []

        # Walk through the entire directory
        for root, dirs, files in os.walk(search_dir):
            # Skip quarantine folder — contains known-wrong files from AcoustID verification
            dirs[:] = [d for d in dirs if d != 'ss_quarantine']
            for file in files:
                # Direct basename match
                if os.path.basename(file) == target_basename:
                    file_path = os.path.join(root, file)
                    # Fast path: if path aligns with expected directory structure, return now
                    if api_dir_parts and _path_matches_api_dirs(file_path):
                        logger.info(f"Found path-confirmed match in {location_name}: {file_path}")
                        return file_path, 1.0
                    if not api_dir_parts:
                        # No directory info to disambiguate — return first match (original behavior)
                        logger.info(f"Found exact match in {location_name}: {file_path}")
                        return file_path, 1.0
                    exact_matches.append(file_path)
                    continue

                # Check for slskd dedup suffix (e.g. "Song_639067852665564677.flac")
                # slskd appends _<timestamp> when a file with the same name already exists
                file_stem, file_ext_part = os.path.splitext(file)
                stripped_stem = re.sub(r'_\d{10,}$', '', file_stem)
                if stripped_stem != file_stem and stripped_stem + file_ext_part == target_basename:
                    file_path = os.path.join(root, file)
                    if api_dir_parts and _path_matches_api_dirs(file_path):
                        logger.info(f"Found path-confirmed dedup match in {location_name}: {file_path}")
                        return file_path, 1.0
                    if not api_dir_parts:
                        logger.info(f"Found dedup-suffix match in {location_name}: {file_path}")
                        return file_path, 1.0
                    exact_matches.append(file_path)
                    continue

                # Fuzzy matching for variations
                normalized_file = normalize_for_finding(file)
                similarity = SequenceMatcher(None, normalized_target, normalized_file).ratio()

                if similarity > highest_fuzzy_similarity:
                    highest_fuzzy_similarity = similarity
                    best_fuzzy_path = os.path.join(root, file)

        # Return best exact match (disambiguated by path), or fall back to fuzzy
        if exact_matches:
            if len(exact_matches) == 1:
                logger.info(f"Found exact match in {location_name}: {exact_matches[0]}")
                return exact_matches[0], 1.0
            # Multiple files share the basename — pick the one whose path best
            # matches the expected directory structure from the Soulseek remote path
            best = exact_matches[0]
            best_score = -1
            for m in exact_matches:
                m_parts = set(p.lower() for p in m.replace('\\', '/').split('/'))
                score = sum(1 for d in api_dir_parts if d in m_parts)
                if score > best_score:
                    best_score = score
                    best = m
            logger.info(f"Found {len(exact_matches)} files named '{target_basename}' in {location_name}, picked best path match: {best}")
            return best, 1.0

        return best_fuzzy_path, highest_fuzzy_similarity

    # Extract filename using the helper function
    target_basename = extract_filename(api_filename)
    normalized_target = normalize_for_finding(target_basename)

    # Extract directory components from the API path for disambiguation.
    # When multiple downloads produce the same basename (e.g., "01 - Silent Night.flac"
    # from different albums/users), these let us pick the correct file on disk.
    api_path_normalized = api_filename.replace('\\', '/') if api_filename else ''
    api_dir_parts = [p.lower() for p in api_path_normalized.split('/')[:-1] if p]

    # First search in downloads directory
    best_downloads_path, downloads_similarity = search_in_directory(download_dir, 'downloads')

    # Use a high confidence threshold for fuzzy matches to prevent false positives
    if downloads_similarity > 0.85:
        location = 'downloads'
        if downloads_similarity < 1.0:
            logger.info(f"Found fuzzy match in downloads ({downloads_similarity:.2f}): {best_downloads_path}")
        return (best_downloads_path, location)

    # If not found in downloads and transfer_dir is provided, search there
    transfer_similarity = 0.0  # Initialize transfer_similarity
    if transfer_dir and os.path.exists(transfer_dir):
        best_transfer_path, transfer_similarity = search_in_directory(transfer_dir, 'transfer')

        if transfer_similarity > 0.85:
            location = 'transfer'
            if transfer_similarity < 1.0:
                logger.info(f"Found fuzzy match in transfer ({transfer_similarity:.2f}): {best_transfer_path}")
            return (best_transfer_path, location)

    # Don't spam logs - file not found is common for completed/processed downloads
    return (None, None)




@app.route('/api/downloads/status')
def get_download_status():
    """
    A robust status checker that correctly finds completed files by searching
    the entire download directory with fuzzy matching, mirroring the logic from downloads.py.
    """
    if not soulseek_client:
        return jsonify({"transfers": []})

    try:
        global processed_download_ids
        # Skip slskd API call if Soulseek is already known to be disconnected
        soulseek_known_down = not _status_cache.get('soulseek', {}).get('connected', True)
        transfers_data = None
        if not soulseek_known_down:
            transfers_data = run_async(soulseek_client._make_request('GET', 'transfers/downloads'))

        # Don't return early if no Soulseek transfers - YouTube/Tidal downloads need to be checked too!
        all_transfers = []
        completed_matched_downloads = []
        # Track files already claimed this poll cycle to prevent two contexts from
        # grabbing the same physical file when downloads share a basename (e.g.,
        # "07 - Aurora.flac" from two different albums/artists).
        _files_claimed_this_cycle = set()

        if not transfers_data:
            # No Soulseek transfers, but continue to check YouTube/Tidal downloads below
            pass
        else:
            # This logic now correctly processes the nested structure from the slskd API
            for user_data in transfers_data:
                username = user_data.get('username', 'Unknown')
                if 'directories' in user_data:
                    for directory in user_data['directories']:
                        if 'files' in directory:
                            for file_info in directory['files']:
                                file_info['username'] = username
                                all_transfers.append(file_info)
                                state = file_info.get('state', '').lower()

                                # Check for completion state
                                if ('succeeded' in state or 'completed' in state) and 'errored' not in state and 'rejected' not in state:
                                    # Verify bytes actually transferred before trusting state
                                    _fi_size = file_info.get('size', 0)
                                    _fi_transferred = file_info.get('bytesTransferred', 0)
                                    if _fi_size > 0 and _fi_transferred < _fi_size:
                                        continue  # Not truly complete yet
                                    filename_from_api = file_info.get('filename')
                                    if not filename_from_api: continue

                                    # Check if this completed download has a matched context
                                    context_key = _make_context_key(username, filename_from_api)

                                    # Check if this is an orphaned download that completed after retry
                                    if context_key in _orphaned_download_keys:
                                        # Safety check: if a new context exists for this key, the retry
                                        # re-claimed the same source — treat it as active, not orphaned
                                        with matched_context_lock:
                                            has_active_context = context_key in matched_downloads_context
                                        if has_active_context:
                                            logger.warning(f"Orphaned key {context_key} has active context — retry re-used same source, treating as active")
                                            _orphaned_download_keys.discard(context_key)
                                            # Fall through to normal processing below
                                        else:
                                            download_dir = docker_resolve_path(config_manager.get('soulseek.download_path', './downloads'))
                                            found_result = _find_completed_file_robust(download_dir, filename_from_api)
                                            found_path = found_result[0] if found_result and found_result[0] else None
                                            orphan_cleaned = False
                                            if found_path:
                                                try:
                                                    os.remove(found_path)
                                                    logger.warning(f"Deleted orphaned download: {os.path.basename(found_path)}")
                                                    orphan_cleaned = True
                                                except Exception as e:
                                                    logger.error(f"Failed to delete orphaned file (will retry next poll): {e}")
                                            else:
                                                # File not on disk (already gone or never written) — nothing to clean
                                                orphan_cleaned = True
                                            if orphan_cleaned:
                                                # Remove transfer from slskd
                                                transfer_id = file_info.get('id')
                                                if transfer_id:
                                                    try:
                                                        run_async(soulseek_client.cancel_download(str(transfer_id), username, remove=True))
                                                    except Exception:
                                                        pass
                                                _orphaned_download_keys.discard(context_key)
                                            continue  # Skip normal post-processing either way

                                    # Skip downloads we've already processed (prevents log spam)
                                    if context_key in processed_download_ids:
                                        continue

                                    with matched_context_lock:
                                        context = matched_downloads_context.get(context_key)
                                        available_keys = list(matched_downloads_context.keys())[:5] if not context else None

                                    if context:
                                        logger.info(f"[Context Lookup] Found context for key: {context_key}")
                                    elif context_key not in _stale_transfer_keys:
                                        # Only log once per stale key to avoid spamming every poll cycle
                                        logger.warning(f"[Context Lookup] No context found for key: {context_key}")
                                        logger.info(f"   Available keys: {available_keys}...")
                                        _stale_transfer_keys.add(context_key)

                                    if context:
                                        download_dir = docker_resolve_path(config_manager.get('soulseek.download_path', './downloads'))
                                        # Use the new robust file finder (only search downloads for post-processing candidates)
                                        found_result = _find_completed_file_robust(download_dir, filename_from_api)
                                        found_path = found_result[0] if found_result and found_result[0] else None

                                        if found_path:
                                            # Prevent two contexts from claiming the same physical file
                                            _norm_path = os.path.normpath(found_path)
                                            if _norm_path in _files_claimed_this_cycle:
                                                logger.info(f"File already claimed by another context this cycle: {os.path.basename(found_path)} — deferring to next poll")
                                            else:
                                                _files_claimed_this_cycle.add(_norm_path)
                                                logger.info(f"Found completed matched file on disk: {found_path}")
                                                completed_matched_downloads.append((context_key, context, found_path))
                                                # Don't add to processed_download_ids yet - wait until thread starts successfully

                                                # Clean up retry tracking if file was found after retries
                                                with _download_retry_lock:
                                                    if context_key in _download_retry_attempts:
                                                        retry_count = _download_retry_attempts[context_key]['count']
                                                        elapsed = time.time() - _download_retry_attempts[context_key]['first_attempt']
                                                        logger.warning(f"File found after {retry_count} retry attempt(s) ({elapsed:.1f}s): {os.path.basename(filename_from_api)}")
                                                        del _download_retry_attempts[context_key]
                                        else:
                                            # File not found yet - implement retry logic instead of immediate give-up
                                            # This fixes race condition where slskd reports completion before file is written to disk
                                            with _download_retry_lock:
                                                if context_key not in _download_retry_attempts:
                                                    # First retry attempt
                                                    _download_retry_attempts[context_key] = {
                                                        'count': 1,
                                                        'first_attempt': time.time()
                                                    }
                                                    logger.warning(f"File not found yet: '{os.path.basename(filename_from_api)}' - Will retry (attempt 1/{_download_retry_max})")
                                                else:
                                                    # Increment retry count
                                                    _download_retry_attempts[context_key]['count'] += 1
                                                    retry_count = _download_retry_attempts[context_key]['count']
                                                    elapsed = time.time() - _download_retry_attempts[context_key]['first_attempt']

                                                    if retry_count >= _download_retry_max:
                                                        # Max retries reached, give up
                                                        logger.error(f"CRITICAL: Could not find '{os.path.basename(filename_from_api)}' after {retry_count} attempts over {elapsed:.1f}s. Giving up.")
                                                        processed_download_ids.add(context_key)
                                                        # Clean up retry tracking
                                                        del _download_retry_attempts[context_key]
                                                    else:
                                                        logger.warning(f"File not found yet: '{os.path.basename(filename_from_api)}' - Will retry (attempt {retry_count}/{_download_retry_max}, elapsed: {elapsed:.1f}s)")

        # If we found completed matched downloads, start processing them in background threads
        if completed_matched_downloads:
            def process_completed_downloads():
                for context_key, context, found_path in completed_matched_downloads:
                    try:
                        logger.info(f"Starting post-processing thread for: {context_key}")
                        # Use verification wrapper if context has task tracking IDs,
                        # otherwise call directly (race guard flag still gets set on context)
                        _pp_task_id = context.get('task_id')
                        _pp_batch_id = context.get('batch_id')
                        if _pp_task_id and _pp_batch_id:
                            _pp_target = _post_process_matched_download_with_verification
                            _pp_args = (context_key, context, found_path, _pp_task_id, _pp_batch_id)
                        else:
                            _pp_target = _post_process_matched_download
                            _pp_args = (context_key, context, found_path)
                        thread = threading.Thread(target=_pp_target, args=_pp_args)
                        thread.daemon = True
                        thread.start()

                        # Only mark as processed AFTER thread starts successfully
                        processed_download_ids.add(context_key)
                        logger.info(f"Marked as processed: {context_key}")

                        # DON'T remove context immediately - verification worker needs it
                        # Context will be cleaned up by verification worker after both processors complete
                        logger.info(f"Keeping context for verification worker: {context_key}")

                    except Exception as e:
                        logger.error(f"Error starting post-processing thread for {context_key}: {e}")
                        # Don't add to processed set if thread failed to start
                        logger.warning(f"Will retry {context_key} on next check")

            # Start a single thread to manage the launching of all processing threads
            processing_thread = threading.Thread(target=process_completed_downloads)
            processing_thread.daemon = True
            processing_thread.start()

        # Also include YouTube/Tidal downloads in the response
        try:
            all_streaming_downloads = run_async(soulseek_client.get_all_downloads())

            for download in all_streaming_downloads:
                if download.username in ('youtube', 'tidal', 'qobuz', 'hifi', 'deezer_dl', 'lidarr'):
                    source_label = download.username.title()
                    # Convert DownloadStatus to transfer format that frontend expects
                    streaming_transfer = {
                        'id': download.id,
                        'filename': download.filename,
                        'username': download.username,
                        'state': download.state,
                        'percentComplete': download.progress,
                        'size': download.size,
                        'bytesTransferred': download.transferred,
                        'averageSpeed': download.speed,
                        'direction': 'Download',  # Required by frontend
                    }
                    all_transfers.append(streaming_transfer)

                    # Check if download is completed and needs post-processing
                    # Verify bytes match before trusting state string
                    _st_bytes_ok = download.size <= 0 or download.transferred >= download.size
                    if _st_bytes_ok and download.state and ('succeeded' in download.state.lower() or 'completed' in download.state.lower()):
                        context_key = _make_context_key(download.username, download.filename)

                        with matched_context_lock:
                            context = matched_downloads_context.get(context_key)

                        if context and context_key not in processed_download_ids:
                            download_dir = docker_resolve_path(config_manager.get('soulseek.download_path', './downloads'))
                            found_result = _find_completed_file_robust(download_dir, download.filename)
                            found_path = found_result[0] if found_result and found_result[0] else None

                            if found_path:
                                # Prevent two contexts from claiming the same physical file
                                _st_norm = os.path.normpath(found_path)
                                if _st_norm in _files_claimed_this_cycle:
                                    logger.info(f"[{source_label}] File already claimed this cycle: {os.path.basename(found_path)} — deferring")
                                    continue
                                _files_claimed_this_cycle.add(_st_norm)
                                logger.info(f"[{source_label}] Found completed matched file on disk: {found_path}")
                                # Start post-processing thread
                                def process_streaming_download(_ctx_key=context_key, _ctx=context, _path=found_path, _label=source_label):
                                    try:
                                        logger.info(f"[{_label}] Starting post-processing thread for: {_ctx_key}")
                                        # Use verification wrapper if context has task tracking IDs
                                        _st_task_id = _ctx.get('task_id')
                                        _st_batch_id = _ctx.get('batch_id')
                                        if _st_task_id and _st_batch_id:
                                            _st_target = _post_process_matched_download_with_verification
                                            _st_args = (_ctx_key, _ctx, _path, _st_task_id, _st_batch_id)
                                        else:
                                            _st_target = _post_process_matched_download
                                            _st_args = (_ctx_key, _ctx, _path)
                                        thread = threading.Thread(target=_st_target, args=_st_args)
                                        thread.daemon = True
                                        thread.start()
                                        processed_download_ids.add(_ctx_key)
                                        logger.info(f"[{_label}] Marked as processed: {_ctx_key}")
                                    except Exception as e:
                                        logger.error(f"[{_label}] Error starting post-processing thread for {_ctx_key}: {e}")

                                processing_thread = threading.Thread(target=process_streaming_download)
                                processing_thread.daemon = True
                                processing_thread.start()
                            else:
                                # File not found - likely already processed and moved to library
                                # Mark as processed to prevent infinite checking
                                processed_download_ids.add(context_key)
        except Exception as streaming_error:
            import traceback
            logger.error(f"Could not fetch YouTube/Tidal downloads for status: {streaming_error}")
            traceback.print_exc()

        # Enrich transfers with metadata from download context (artist, album, artwork)
        with matched_context_lock:
            for transfer in all_transfers:
                ctx_key = _make_context_key(transfer.get('username', ''), transfer.get('filename', ''))
                ctx = matched_downloads_context.get(ctx_key)
                if ctx:
                    _sp_artist = ctx.get('spotify_artist') or {}
                    _sp_album = ctx.get('spotify_album') or {}
                    _sp_track = ctx.get('track_info') or {}
                    # Cover art can live in a few places depending on the
                    # origin path: album.images[0].url (Spotify-shaped),
                    # album.image_url (context-built / wishlist / fixes), or
                    # track_info.image_url (some discovery flows). Try them
                    # all so fixed-discovery tracks render their artwork.
                    _sp_images = _sp_album.get('images') or []
                    _art_url = ''
                    if _sp_images and isinstance(_sp_images[0], dict):
                        _art_url = _sp_images[0].get('url', '') or ''
                    if not _art_url:
                        _art_url = _sp_album.get('image_url') or ''
                    if not _art_url:
                        _art_url = _sp_track.get('image_url') or ''
                    transfer['_meta'] = {
                        'artist': _sp_artist.get('name', ''),
                        'album': _sp_album.get('name', ''),
                        'artwork_url': _art_url,
                        'track_number': _sp_track.get('track_number'),
                        'quality': ctx.get('_audio_quality', ''),
                    }

        return jsonify({"transfers": all_transfers})

    except Exception as e:
        logger.error(f"Error fetching download status: {e}")
        return jsonify({"error": str(e)}), 500





# Cancel + clear logic lives in core/downloads/cancel.py — these routes are thin handlers.
from core.downloads import cancel as _downloads_cancel


@app.route('/api/downloads/cancel', methods=['POST'])
def cancel_download():
    """Cancel a specific download transfer, matching GUI functionality."""
    data = request.get_json()
    if not data:
        return jsonify({"success": False, "error": "No data provided."}), 400

    download_id = data.get('download_id')
    username = data.get('username')

    if not all([download_id, username]):
        return jsonify({"success": False, "error": "Missing download_id or username."}), 400

    try:
        success = _downloads_cancel.cancel_single_download(soulseek_client, run_async, download_id, username)
        if success:
            return jsonify({"success": True, "message": "Download cancelled."})
        return jsonify({"success": False, "error": "Failed to cancel download via slskd."}), 500
    except Exception as e:
        logger.error(f"Error cancelling download: {e}")
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/downloads/cancel-all', methods=['POST'])
def cancel_all_downloads():
    """Cancel all active downloads from slskd, then clear completed ones."""
    try:
        success, msg = _downloads_cancel.cancel_all_active(
            soulseek_client, run_async, _sweep_empty_download_directories,
        )
        if success:
            return jsonify({"success": True, "message": msg})
        return jsonify({"success": False, "error": msg}), 500
    except Exception as e:
        logger.error(f"Error cancelling all downloads: {e}")
        return jsonify({"success": False, "error": str(e)}), 500


