@app.route('/api/artist/<artist_id>/completion-stream', methods=['POST'])
def check_artist_discography_completion_stream(artist_id):
    """Stream completion status for artist's albums and singles one by one"""
    # Capture request data BEFORE the generator function
    try:
        data = request.get_json()
        if not data or 'discography' not in data:
            return jsonify({"error": "Missing discography data"}), 400
    except Exception as e:
        return jsonify({"error": "Invalid request data"}), 400
    
    # Extract data for the generator
    discography = data['discography']
    artist_name = data.get('artist_name', 'Unknown Artist')
    source_override = (data.get('source') or '').strip().lower() or None
    from core.metadata_service import iter_artist_discography_completion_events

    def generate_completion_stream():
        try:
            logger.info(f"Starting streaming completion check for artist: {artist_name}")
            for event in iter_artist_discography_completion_events(
                discography,
                artist_name=artist_name,
                source_override=source_override,
            ):
                yield f"data: {json.dumps(event)}\n\n"
                if event.get('type') in ('album_completion', 'single_completion'):
                    # Small delay to make the streaming effect visible
                    time.sleep(0.1)  # 100ms delay between items
        except Exception as e:
            logger.error(f"Error in streaming completion check: {e}")
            import traceback
            traceback.print_exc()
            yield f"data: {json.dumps({'type': 'error', 'error': str(e)})}\n\n"
    
    return Response(
        generate_completion_stream(),
        content_type='text/event-stream',
        headers={
            'Cache-Control': 'no-cache',
            'Connection': 'keep-alive',
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Headers': 'Cache-Control'
        }
    )

@app.route('/api/library/completion-stream', methods=['POST'])
def library_completion_stream():
    """Stream completion status for library artist detail view - checks ownership per release via SSE"""
    try:
        data = request.get_json()
        if not data or 'artist_name' not in data:
            return jsonify({"error": "Missing artist_name"}), 400
    except Exception as e:
        return jsonify({"error": "Invalid request data"}), 400

    artist_name = data['artist_name']

    def generate():
        try:
            from core.metadata_service import check_album_completion, check_single_completion
            db = get_database()
            source_override = (data.get('source') or '').strip().lower() or None

            categories = ['albums', 'eps', 'singles']
            all_items = []
            for cat in categories:
                for item in data.get(cat, []):
                    all_items.append((cat, item))

            # Pre-fetch the artist's library albums AND tracks ONCE so per-item
            # matching runs in-memory instead of firing per-item SQL searches.
            # Turns N*K queries into 2 broad fetches + N track-count lookups.
            from config.settings import config_manager as _cm_cs
            _active_server = _cm_cs.get_active_media_server()
            candidate_albums = None
            candidate_tracks = None
            _t0 = time.perf_counter()
            try:
                candidate_albums = db.get_candidate_albums_for_artist(artist_name, server_source=_active_server)
            except Exception as _cand_err:
                print(f"[completion-stream] Failed to pre-fetch album candidates for '{artist_name}': {_cand_err}")
                candidate_albums = None
            _t1 = time.perf_counter()
            print(f"[completion-stream] Pre-fetched {len(candidate_albums) if candidate_albums is not None else 0} library albums for '{artist_name}' in {(_t1 - _t0) * 1000:.0f}ms")

            if candidate_albums:
                _t2 = time.perf_counter()
                try:
                    candidate_tracks = db.get_candidate_tracks_for_albums([a.id for a in candidate_albums])
                except Exception as _tr_err:
                    print(f"[completion-stream] Failed to pre-fetch track candidates for '{artist_name}': {_tr_err}")
                    candidate_tracks = None
                _t3 = time.perf_counter()
                print(f"[completion-stream] Pre-fetched {len(candidate_tracks) if candidate_tracks is not None else 0} library tracks in {(_t3 - _t2) * 1000:.0f}ms")

            yield f"data: {json.dumps({'type': 'start', 'total_items': len(all_items)})}\n\n"

            _loop_start = time.perf_counter()
            for _i, (category, item) in enumerate(all_items):
                try:
                    # Map Library field names to helper field names
                    mapped = {
                        'id': item['id'],
                        'name': item['title'],
                        'total_tracks': item.get('track_count', 0),
                        'album_type': item.get('album_type', 'album')
                    }

                    if category == 'singles':
                        result = check_single_completion(db, mapped, artist_name, source_override=source_override, candidate_albums=candidate_albums, candidate_tracks=candidate_tracks)
                    else:
                        result = check_album_completion(db, mapped, artist_name, source_override=source_override, candidate_albums=candidate_albums)

                    result['id'] = item['id']
                    result['category'] = category
                    result['type'] = 'completion'
                    yield f"data: {json.dumps(result)}\n\n"
                except Exception as e:
                    yield f"data: {json.dumps({'type': 'completion', 'category': category, 'id': item['id'], 'status': 'error', 'owned_tracks': 0, 'expected_tracks': item.get('track_count', 0), 'completion_percentage': 0, 'confidence': 0.0, 'error': str(e)})}\n\n"

                time.sleep(0.05)  # 50ms between items for visible streaming

            _loop_elapsed = time.perf_counter() - _loop_start
            _sleep_floor = 0.05 * len(all_items)
            print(f"[completion-stream] Processed {len(all_items)} items for '{artist_name}' in {_loop_elapsed * 1000:.0f}ms (sleep floor: {_sleep_floor * 1000:.0f}ms)")

            yield f"data: {json.dumps({'type': 'complete', 'processed_count': len(all_items)})}\n\n"

        except Exception as e:
            logger.error(f"Error in library completion stream: {e}")
            import traceback
            traceback.print_exc()
            yield f"data: {json.dumps({'type': 'error', 'error': str(e)})}\n\n"

    return Response(
        generate(),
        content_type='text/event-stream',
        headers={
            'Cache-Control': 'no-cache',
            'Connection': 'keep-alive',
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Headers': 'Cache-Control'
        }
    )

@app.route('/api/library/check-tracks', methods=['POST'])
def library_check_tracks():
    """Check which tracks from a list are already owned in the library.
    Uses a single batch DB query + in-memory fuzzy matching for speed."""
    try:
        data = request.get_json()
        if not data or 'artist_name' not in data or 'tracks' not in data:
            return jsonify({"success": False, "error": "Missing artist_name or tracks"}), 400

        artist_name = data['artist_name']
        tracks = data['tracks']

        from database.music_database import MusicDatabase
        db = MusicDatabase()
        active_server = config_manager.get_active_media_server()

        # Single query: get ALL tracks by this artist from the DB
        db_tracks = db.search_tracks(artist=artist_name, limit=500, server_source=active_server)

        if not db_tracks:
            # No tracks by this artist in DB — none owned
            owned_map = {t.get('name', ''): {"owned": False} for t in tracks if t.get('name')}
            return jsonify({"success": True, "owned_tracks": owned_map})

        # Pre-normalize all DB track titles for fast in-memory comparison
        from difflib import SequenceMatcher
        try:
            from unidecode import unidecode
        except ImportError:
            unidecode = lambda x: x

        def _normalize(text):
            if not text:
                return ""
            return unidecode(text).lower().strip()

        def _clean_title(text):
            import re
            cleaned = _normalize(text)
            # Remove parenthetical/bracket content, dashes, feat/ft, remaster tags
            cleaned = re.sub(r'\s*[\[\(].*?[\]\)]', '', cleaned)
            cleaned = re.sub(r'\s*-\s*', ' ', cleaned)
            cleaned = re.sub(r'\s*feat\..*', '', cleaned)
            cleaned = re.sub(r'\s*featuring.*', '', cleaned)
            cleaned = re.sub(r'\s*ft\..*', '', cleaned)
            cleaned = re.sub(r'\s*\d{4}\s*remaster.*', '', cleaned)
            cleaned = re.sub(r'\s*remaster(ed)?.*', '', cleaned)
            cleaned = re.sub(r'\s+', ' ', cleaned).strip()
            return cleaned

        # Pre-compute normalized DB titles once (keep reference to db_track for metadata)
        db_title_entries = [(_normalize(t.title), _clean_title(t.title), t) for t in db_tracks]

        # Album-aware matching: if album_name provided, prefer tracks from that album
        target_album = data.get('album_name', '')
        target_album_norm = _normalize(target_album) if target_album else ''

        def _match_title(search_norm, search_clean, candidates):
            """Find best matching track from a list of (norm, clean, db_track) candidates."""
            for db_norm, db_clean, db_track in candidates:
                if search_norm == db_norm or search_clean == db_clean:
                    return db_track
                sim = max(
                    SequenceMatcher(None, search_norm, db_norm).ratio(),
                    SequenceMatcher(None, search_clean, db_clean).ratio()
                )
                if sim >= 0.7:
                    return db_track
            return None

        # Split DB tracks by album if album-aware matching is active
        album_entries = []
        other_entries = []
        if target_album_norm:
            for entry in db_title_entries:
                db_album = _normalize(getattr(entry[2], 'album_title', '') or '')
                if db_album and SequenceMatcher(None, target_album_norm, db_album).ratio() >= 0.7:
                    album_entries.append(entry)
                else:
                    other_entries.append(entry)
        else:
            other_entries = db_title_entries

        owned_map = {}
        for track in tracks:
            track_name = track.get('name', '')
            if not track_name:
                continue

            search_norm = _normalize(track_name)
            search_clean = _clean_title(track_name)

            # When album context provided, only match within that album —
            # prevents false positives where "Thriller" on Album A shows as owned
            # because it exists on Album B. Without album context, search all tracks.
            if target_album_norm:
                matched_db_track = _match_title(search_norm, search_clean, album_entries)
            else:
                matched_db_track = _match_title(search_norm, search_clean, other_entries)

            if matched_db_track:
                import os
                file_ext = os.path.splitext(matched_db_track.file_path or '')[1].lstrip('.').upper() or None
                owned_map[track_name] = {
                    "owned": True,
                    "format": file_ext,
                    "bitrate": matched_db_track.bitrate,
                    "album": getattr(matched_db_track, 'album_title', None)
                }
            else:
                owned_map[track_name] = {"owned": False}

        return jsonify({"success": True, "owned_tracks": owned_map})

    except Exception as e:
        logger.error(f"Error checking track ownership: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500


