# ── Update detection ─────────────────────────────────────────────
_GITHUB_REPO = "Nezreka/SoulSync"
_update_cache = {'latest_sha': None, 'last_check': 0, 'error': None}
_UPDATE_CHECK_INTERVAL = 3600  # 1 hour

def _get_current_commit_sha():
    """Get the commit SHA of the running instance (env var for Docker, git for local)."""
    # Docker: baked in at build time via COMMIT_SHA build arg
    sha = os.environ.get('SOULSYNC_COMMIT_SHA', '').strip()
    if sha:
        return sha
    # Local dev: read from git
    try:
        import subprocess
        result = subprocess.run(['git', 'rev-parse', 'HEAD'], capture_output=True, text=True, cwd=os.path.dirname(__file__) or '.')
        if result.returncode == 0:
            return result.stdout.strip()
    except Exception:
        pass
    return None

_current_commit_sha = _get_current_commit_sha()

def _check_for_updates():
    """Check GitHub for the latest commit SHA on main branch."""
    import time as _time
    now = _time.time()
    if now - _update_cache['last_check'] < _UPDATE_CHECK_INTERVAL:
        return  # Still fresh
    _update_cache['last_check'] = now
    try:
        import urllib.request
        import json as _json
        req = urllib.request.Request(
            f"https://api.github.com/repos/{_GITHUB_REPO}/commits/main",
            headers={'Accept': 'application/vnd.github.v3+json', 'User-Agent': 'SoulSync-UpdateCheck'}
        )
        with urllib.request.urlopen(req, timeout=10) as resp:
            data = _json.loads(resp.read().decode())
            _update_cache['latest_sha'] = data.get('sha')
            _update_cache['error'] = None
    except Exception as e:
        _update_cache['error'] = str(e)
        logger.debug(f"Update check failed: {e}")

@app.route('/api/update-check', methods=['GET'])
def check_for_update():
    """Check if a newer version is available on GitHub."""
    _check_for_updates()
    current = _current_commit_sha
    latest = _update_cache.get('latest_sha')
    update_available = bool(current and latest and current != latest)
    return jsonify({
        'update_available': update_available,
        'current_sha': current[:8] if current else None,
        'latest_sha': latest[:8] if latest else None,
        'is_docker': os.path.exists('/.dockerenv'),
    })


def _simple_monitor_task():
    """The actual monitoring task that runs in the background thread.
    Search cleanup and download cleanup are now handled by system automations."""
    logger.info("Simple background monitor started")

    while not globals().get('IS_SHUTTING_DOWN', False):
        try:
            with matched_context_lock:
                pending_count = len(matched_downloads_context)

            if pending_count > 0:
                # Use app_context to safely call endpoint logic from a thread
                with app.app_context():
                    get_download_status()

            # Cleanup stale retry attempts (older than 60 seconds)
            # This prevents memory leaks from stuck/failed downloads
            with _download_retry_lock:
                current_time = time.time()
                stale_keys = [
                    key for key, data in _download_retry_attempts.items()
                    if current_time - data['first_attempt'] > 60
                ]
                for key in stale_keys:
                    logger.warning(f"Cleaning up stale retry attempt: {key}")
                    del _download_retry_attempts[key]

            time.sleep(1)
        except Exception as e:
            logger.error(f"Simple monitor error: {e}")
            time.sleep(10)

    logger.info("Simple background monitor stopped")

def start_simple_background_monitor():
    """Starts the simple background monitor thread."""
    monitor_thread = threading.Thread(target=_simple_monitor_task)
    monitor_thread.daemon = True
    monitor_thread.start()

def check_and_recover_stuck_flags():
    """
    Check if wishlist_auto_processing or watchlist_auto_scanning flags are stuck.
    If a flag has been True for more than 2 hours (7200 seconds), reset it.
    This prevents indefinite blocking when processes crash without cleanup.
    """
    global wishlist_auto_processing, wishlist_auto_processing_timestamp
    global watchlist_auto_scanning, watchlist_auto_scanning_timestamp

    import time
    current_time = time.time()
    stuck_timeout = 900  # 15 minutes in seconds (reduced from 2 hours for faster recovery)

    def _reset_wishlist_processing_state():
        global wishlist_auto_processing, wishlist_auto_processing_timestamp
        with wishlist_timer_lock:
            wishlist_auto_processing = False
            wishlist_auto_processing_timestamp = 0

    # Check wishlist flag
    if _reset_wishlist_flag_if_stuck(
        wishlist_auto_processing,
        wishlist_auto_processing_timestamp,
        timeout_seconds=stuck_timeout,
        now=current_time,
        label="Wishlist auto-processing",
        reset_callback=_reset_wishlist_processing_state,
    ):
        return True

    # Check watchlist flag
    if watchlist_auto_scanning:
        time_stuck = current_time - watchlist_auto_scanning_timestamp
        if time_stuck > stuck_timeout:
            stuck_minutes = time_stuck / 60
            logger.info(f"[Stuck Detection] Watchlist auto-scanning flag has been stuck for {stuck_minutes:.1f} minutes - RESETTING")
            with watchlist_timer_lock:
                watchlist_auto_scanning = False
                watchlist_auto_scanning_timestamp = 0
            return True

    return False

def is_wishlist_actually_processing():
    """
    Check if wishlist is truly processing (not just flag stuck).
    Returns True only if flag is set AND timestamp is recent (< 15 minutes).
    """
    global wishlist_auto_processing, wishlist_auto_processing_timestamp

    import time
    current_time = time.time()

    return _is_wishlist_actually_processing(
        wishlist_auto_processing,
        wishlist_auto_processing_timestamp,
        timeout_seconds=900,
        now=current_time,
        on_stuck=check_and_recover_stuck_flags,
    )

def is_watchlist_actually_scanning():
    """
    Check if watchlist is truly scanning (not just flag stuck).
    Returns True only if flag is set AND timestamp is recent (< 15 minutes).
    """
    global watchlist_auto_scanning, watchlist_auto_scanning_timestamp

    if not watchlist_auto_scanning:
        return False

    import time
    current_time = time.time()
    time_since_start = current_time - watchlist_auto_scanning_timestamp

    # If more than 15 minutes, flag is stuck - auto-recover and return False
    if time_since_start > 900:  # 15 minutes
        stuck_minutes = time_since_start / 60
        logger.warning(f"[Stuck Detection] Watchlist flag stuck for {stuck_minutes:.1f} minutes - auto-recovering")
        check_and_recover_stuck_flags()
        return False

    return True

def _process_wishlist_automatically(automation_id=None):
    """Main automatic processing logic that runs in background thread."""
    global wishlist_auto_processing, wishlist_auto_processing_timestamp
    from core.wishlist_service import get_wishlist_service

    @contextmanager
    def _processing_guard():
        global wishlist_auto_processing, wishlist_auto_processing_timestamp

        with wishlist_timer_lock:
            if wishlist_auto_processing:
                yield False
                return

            wishlist_auto_processing = True
            wishlist_auto_processing_timestamp = time.time()
            logger.info(f"[Auto-Wishlist] Flag set at timestamp {wishlist_auto_processing_timestamp}")

        try:
            yield True
        finally:
            with wishlist_timer_lock:
                wishlist_auto_processing = False
                wishlist_auto_processing_timestamp = 0

    runtime = _WishlistAutoProcessingRuntime(
        processing_guard=_processing_guard,
        is_actually_processing=is_wishlist_actually_processing,
        app_context_factory=lambda: app.app_context(),
        get_profiles_database=get_database,
        get_music_database=MusicDatabase,
        download_batches=download_batches,
        tasks_lock=tasks_lock,
        update_automation_progress=_update_automation_progress,
        automation_engine=automation_engine,
        missing_download_executor=missing_download_executor,
        run_full_missing_tracks_process=_run_full_missing_tracks_process,
        get_batch_max_concurrent=_get_batch_max_concurrent,
        get_active_server=config_manager.get_active_media_server,
        current_time_fn=time.time,
        profile_id=1,
    )

    _process_wishlist_automatically_impl(runtime, automation_id=automation_id)

