    """Return cached import suggestions. If cache isn't built yet, returns partial/empty with a flag."""
    cache = get_import_suggestions_cache()
    return jsonify({
        'success': True,
        'suggestions': cache['suggestions'],
        'ready': cache['built'],
    })


