def _emit_sync_progress_loop():
    """Push sync progress to subscribed rooms every 1 second."""
    while not globals().get('IS_SHUTTING_DOWN', False):
        socketio.sleep(1)
        try:
            with sync_lock:
                for pid, state in list(sync_states.items()):
                    try:
                        socketio.emit('sync:progress', {
                            'playlist_id': pid, **state
                        }, room=f'sync:{pid}')
                    except Exception:
                        pass
        except Exception as e:
            logger.debug(f"Error in sync progress loop: {e}")

def _emit_discovery_progress_loop():
    """Push discovery progress to subscribed rooms every 1 second."""
    platform_states = {
        'tidal': lambda: tidal_discovery_states,
        'deezer': lambda: deezer_discovery_states,
        'youtube': lambda: youtube_playlist_states,
        'beatport': lambda: beatport_chart_states,
        'listenbrainz': lambda: listenbrainz_playlist_states,
        'spotify_public': lambda: spotify_public_discovery_states,
    }
    while not globals().get('IS_SHUTTING_DOWN', False):
        socketio.sleep(1)
        for platform_name, get_states in platform_states.items():
            try:
                states_dict = get_states()
                for pid, state in list(states_dict.items()):
                    try:
                        phase = state.get('phase', '')
                        if phase in ('', 'idle'):
                            continue
                        payload = {
                            'platform': platform_name,
                            'id': pid,
                            'phase': state.get('phase'),
                            'status': state.get('status', 'unknown'),
                            'progress': state.get('discovery_progress', 0),
                            'discovery_progress': state.get('discovery_progress', {}),
                            'spotify_matches': state.get('spotify_matches', 0),
                            'spotify_total': state.get('spotify_total', 0),
                            'results': state.get('discovery_results', state.get('results', [])),
                            'complete': state.get('phase') == 'discovered',
                        }
                        socketio.emit('discovery:progress', payload, room=f'discovery:{pid}')
                    except Exception:
                        pass
            except Exception as e:
                logger.debug(f"Error in {platform_name} discovery loop: {e}")

def _emit_scan_status_loop():
    """Push watchlist and media scan status every 2 seconds."""
    while not globals().get('IS_SHUTTING_DOWN', False):
        socketio.sleep(2)
        # Watchlist scan
        try:
            state = watchlist_scan_state.copy()
            if state.get('started_at'):
                state['started_at'] = state['started_at'].isoformat()
            if state.get('completed_at'):
                state['completed_at'] = state['completed_at'].isoformat()
            state.pop('results', None)
            socketio.emit('scan:watchlist', {"success": True, **state})
        except Exception as e:
            logger.debug(f"Error emitting watchlist scan: {e}")
        # Media scan
        try:
            if web_scan_manager:
                scan_status = web_scan_manager.get_scan_status()
                socketio.emit('scan:media', {"success": True, "status": scan_status})
        except Exception as e:
            logger.debug(f"Error emitting media scan: {e}")
        # Wishlist stats (auto-processing detection + countdown refresh)
        try:
            next_run = automation_engine.get_system_automation_next_run_seconds('process_wishlist') if automation_engine else 0
            socketio.emit('wishlist:stats', {
                "is_auto_processing": is_wishlist_actually_processing(),
                "next_run_in_seconds": next_run,
            })
        except Exception as e:
            logger.debug(f"Error emitting wishlist stats: {e}")

def _emit_automation_progress_loop():
    """Push automation:progress events every 1 second for running automations."""
    _auto_progress.emit_progress_loop(
        socketio,
        is_shutting_down=lambda: globals().get('IS_SHUTTING_DOWN', False),
    )

def _emit_repair_progress_loop():
    """Push repair:progress events every 1 second for running repair jobs."""
    while not globals().get('IS_SHUTTING_DOWN', False):
        socketio.sleep(1)
        try:
            if repair_worker is None:
                continue
            # Access the progress states set up during repair worker init
            lock = getattr(repair_worker, '_progress_lock_ref', None)
            states = getattr(repair_worker, '_progress_states_ref', None)
            if lock is None or states is None:
                continue
            with lock:
                active = {}
                stale = []
                now = datetime.now()
                for jid, state in states.items():
                    if state['status'] == 'running':
                        cp = dict(state)
                        cp['log'] = list(state['log'])
                        active[jid] = cp
                    elif state['status'] in ('finished', 'error') and state.get('finished_at'):
                        try:
                            finished_time = datetime.fromisoformat(state['finished_at'])
                            if (now - finished_time).total_seconds() > 60:
                                stale.append(jid)
                        except (ValueError, TypeError):
                            stale.append(jid)
                        # Still include recently finished states so frontend sees final state
                        if jid not in stale:
                            cp = dict(state)
                            cp['log'] = list(state['log'])
                            active[jid] = cp
                for jid in stale:
                    del states[jid]
            if active:
                socketio.emit('repair:progress', active)
        except Exception as e:
            logger.debug(f"Error emitting repair progress: {e}")

# ================================================================================================
# END WEBSOCKET HANDLERS
# ================================================================================================

_runtime_start_lock = threading.Lock()
_runtime_started = False


def start_runtime_services():
    """Start one-time server background services for direct and WSGI launches."""
    global _runtime_started

    with _runtime_start_lock:
        if _runtime_started:
            return

        logger.info("Starting SoulSync runtime services...")

        # Dump SOULSYNC_* env vars for diagnostics (helps debug Docker/Unraid env issues)
        _soulsync_env = {k: v for k, v in os.environ.items() if k.startswith('SOULSYNC_')}
        if _soulsync_env:
            logger.info(f"[Startup] SOULSYNC environment variables: {_soulsync_env}")
        else:
            logger.warning("[Startup] No SOULSYNC_* environment variables detected")

        # Start OAuth callback servers
        logger.info("Starting OAuth callback servers...")
        start_oauth_callback_servers()

        # Startup diagnostics: Check and recover stuck flags
        logger.info("Running startup diagnostics...")
        stuck_flags_recovered = check_and_recover_stuck_flags()
        if stuck_flags_recovered:
            logger.warning("Recovered stuck flags from previous session")
        else:
            logger.warning("No stuck flags detected - system healthy")

        # Start simple background monitor when server starts
        logger.info("Starting simple background monitor...")
        start_simple_background_monitor()
        logger.info("Simple background monitor started (includes automatic search cleanup)")

        # Wishlist/watchlist timers are now managed by AutomationEngine system automations

        # Pre-build import suggestions cache in background
        logger.info("Pre-building import suggestions cache...")
        start_import_suggestions_cache()

        # Initialize app start time for uptime tracking
        app.start_time = time.time()

        # Register action handlers and start automation engine
        _register_automation_handlers()
        if automation_engine:
            try:
                logger.info("Starting automation engine...")
                automation_engine.start()
                logger.info("Automation engine started")
                try:
                    automation_engine.emit('app_started', {})
                except Exception:
                    pass
            except AttributeError as e:
                logger.error(f"Automation engine failed to start: {e}")
                logger.info("   If using Docker, check that your volume mount is /app/data (not /app/database)")
                logger.error(f"Automation engine start error (possible stale Docker volume): {e}")
            except Exception as e:
                logger.error(f"Automation engine failed to start: {e}")
                logger.error(f"Automation engine start error: {e}")

        # Add startup activity
        add_activity_item("", "System Started", "SoulSync Web UI Server initialized", "Now")

        # Start WebSocket background emitters
        logger.info("Starting WebSocket background emitters...")
        # Phase 1: Global pollers
        socketio.start_background_task(_emit_service_status_loop)
        socketio.start_background_task(_emit_watchlist_count_loop)
        socketio.start_background_task(_emit_download_status_loop)
        # Phase 2: Dashboard pollers
        socketio.start_background_task(_emit_system_stats_loop)
        socketio.start_background_task(_emit_activity_feed_loop)
        socketio.start_background_task(_emit_db_stats_loop)
        socketio.start_background_task(_emit_wishlist_count_loop)
        # Phase 3: Enrichment sidebar workers
        socketio.start_background_task(_emit_enrichment_status_loop)
        # Phase 4: Tool progress pollers
        socketio.start_background_task(_emit_tool_progress_loop)
        # Phase 5: Sync/discovery progress + scans
        socketio.start_background_task(_emit_sync_progress_loop)
        socketio.start_background_task(_emit_discovery_progress_loop)
        socketio.start_background_task(_emit_scan_status_loop)
        # Phase 6: Automation progress
        socketio.start_background_task(_emit_automation_progress_loop)
        # Phase 7: Repair job progress
        socketio.start_background_task(_emit_repair_progress_loop)
        # Hydrabase auto-reconnect monitor
        socketio.start_background_task(_hydrabase_reconnect_loop)
        # API Rate Monitor — 1s push for speedometer gauges
        socketio.start_background_task(_emit_rate_monitor_loop)
        # Live log tail — streams new log lines to the log viewer
        socketio.start_background_task(_emit_live_log_loop)
        logger.info("WebSocket emitters started (Phase 1-7: global/dashboard/enrichment/tools/sync/automations/repair + rate monitor + live logs)")

        _runtime_started = True


# Direct execution: python web_server.py (dev/Windows fallback)
# Production should use: gunicorn -c gunicorn.conf.py wsgi:application
if _DIRECT_RUN:
    logger.info("Starting SoulSync Web UI Server...")
    logger.info("Open your browser and navigate to http://127.0.0.1:8008")
    logger.info("Tip: For production, use gunicorn -c gunicorn.conf.py wsgi:application")
    start_runtime_services()
    socketio.run(app, host='0.0.0.0', port=8008, debug=False, allow_unsafe_werkzeug=True)
